// Writes the Starknet entry of the @opaquecash/deployments registry from
// deployments/*.json (the source of truth for live addresses). Mirrors the
// ethereum/infra and solana generators: a redeploy is edit-JSON + regenerate,
// never a hand edit of the generated file.
//
// Usage: node scripts/generate-deployments.mjs [path-to-sdk-repo]

import { readdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = dirname(dirname(fileURLToPath(import.meta.url)));
const sdkRoot = resolve(process.argv[2] ?? join(root, "..", "sdk"));
const outPath = join(sdkRoot, "packages/deployments/src/generated/starknet.ts");

const deployments = {};
for (const file of readdirSync(join(root, "deployments")).sort()) {
  if (!file.endsWith(".json")) continue;
  const d = JSON.parse(readFileSync(join(root, "deployments", file), "utf8"));
  deployments[d.network] = {
    network: d.network,
    chainId: d.chainId,
    nodeUrl: d.nodeUrl,
    ...d.contracts,
    stealthAccountClassHash: d.classHashes.stealthAccount,
    announcerFromBlock: d.announcerFromBlock,
  };
}

const body = `// AUTO-GENERATED by starknet/scripts/generate-deployments.mjs — do not edit.
// Source of truth: starknet/deployments/*.json.
import type { StarknetDeployment } from "../types.js";

/** Opaque Starknet deployments keyed by network. */
export const STARKNET_DEPLOYMENTS: Record<string, StarknetDeployment> = ${JSON.stringify(
  deployments,
  null,
  2,
)};
`;

writeFileSync(outPath, body);
console.log(`wrote ${outPath} (${Object.keys(deployments).join(", ")})`);
